class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length / 2;
        int[] pos = new int[row.length];
        for (int i = 0; i < row.length; i++) {
            pos[row[i]] = i;
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
            int u = row[2 * i];
            int v = u ^ 1;
            if (row[2 * i + 1] != v) {
                ans++;
                int t = pos[v];
                pos[row[2 * i + 1]] = t;
                pos[v] = 2 * i + 1;
                row[t] = row[2 * i + 1];
                row[2 * i + 1] = v;
            }
        }
        return ans;
    }
}
